//! Directory scanner — walks directories, probes audio files, extracts metadata.

use std::path::{Path, PathBuf};

use crate::{JalwaError, MediaItem, Result};
use tarang_core::MediaInfo;

/// Supported audio/media file extensions
const SUPPORTED_EXTENSIONS: &[&str] = &[
    "mp3", "flac", "wav", "ogg", "m4a", "mp4", "mkv", "webm", "aac", "opus",
];

/// A scanned file with extracted metadata
pub struct ScannedFile {
    pub path: PathBuf,
    pub info: MediaInfo,
    pub title: Option<String>,
    pub artist: Option<String>,
    pub album: Option<String>,
}

/// Scan a directory recursively for supported media files.
pub fn scan_directory(path: &Path) -> Result<Vec<ScannedFile>> {
    if !path.is_dir() {
        return Err(JalwaError::Scanner(format!(
            "not a directory: {}",
            path.display()
        )));
    }

    let mut results = Vec::new();

    for entry in walkdir::WalkDir::new(path)
        .follow_links(true)
        .into_iter()
        .filter_map(|e| e.ok())
    {
        let entry_path = entry.path();
        if !entry_path.is_file() {
            continue;
        }

        let ext = entry_path
            .extension()
            .and_then(|e| e.to_str())
            .map(|e| e.to_lowercase());

        match ext {
            Some(e) if SUPPORTED_EXTENSIONS.contains(&e.as_str()) => {}
            _ => continue,
        }

        match scan_file(entry_path) {
            Ok(scanned) => results.push(scanned),
            Err(e) => {
                tracing::warn!(path = %entry_path.display(), error = %e, "skipping file");
            }
        }
    }

    Ok(results)
}

/// Scan a single file: probe with tarang, then extract rich tags with lofty.
fn scan_file(path: &Path) -> Result<ScannedFile> {
    // Probe with tarang for duration/codec/format info
    let file = std::fs::File::open(path)?;
    let info = tarang_audio::probe_audio(file).map_err(JalwaError::Tarang)?;

    // Extract rich tags with lofty
    let (title, artist, album) = match lofty::read_from_path(path) {
        Ok(tagged_file) => {
            use lofty::prelude::*;
            let tag = tagged_file.primary_tag().or_else(|| tagged_file.first_tag());
            match tag {
                Some(t) => (
                    t.title().map(|s| s.to_string()),
                    t.artist().map(|s| s.to_string()),
                    t.album().map(|s| s.to_string()),
                ),
                None => (None, None, None),
            }
        }
        Err(_) => (None, None, None),
    };

    Ok(ScannedFile {
        path: path.to_path_buf(),
        info,
        title,
        artist,
        album,
    })
}

/// Convert a scanned file to a MediaItem, preferring lofty tags over probe-derived metadata.
pub fn scanned_to_media_item(scanned: ScannedFile) -> MediaItem {
    let mut item = MediaItem::from_probe(scanned.path, &scanned.info);

    // Override with richer lofty tags
    if let Some(title) = scanned.title {
        item.title = title;
    }
    if scanned.artist.is_some() {
        item.artist = scanned.artist;
    }
    if scanned.album.is_some() {
        item.album = scanned.album;
    }

    item
}

//! Decode loop — runs on a dedicated OS thread.
//!
//! Reads packets from a `FileDecoder`, resamples/mixes as needed, applies
//! volume, and writes to audio output. Receives commands from the engine
//! via an `mpsc` channel and pushes status updates back via a `watch`.

use std::path::PathBuf;
use std::sync::{Arc, Mutex, mpsc};
use std::time::Duration;

use tarang_audio::{AudioOutput, ChannelLayout, FileDecoder, OutputConfig, mix_channels, resample};
use tarang_core::TarangError;

use crate::EngineConfig;

/// Commands sent from the engine to the decode thread.
#[derive(Debug)]
pub enum EngineCommand {
    Play,
    Pause,
    Resume,
    Stop,
    Seek(Duration),
    Volume(f32),
    Mute(bool),
    PrepareNext { path: PathBuf },
}

/// Events sent from the decode thread back to the engine / UI.
#[derive(Debug, Clone)]
pub enum EngineEvent {
    StateChanged(jalwa_core::PlaybackState),
    PositionUpdate(Duration),
    TrackFinished,
    TrackChanged,
    NearEnd,
    Error(String),
}

/// Snapshot of decode‐thread state, published via `watch`.
#[derive(Debug, Clone)]
pub struct DecodeStatus {
    pub state: jalwa_core::PlaybackState,
    pub position: Duration,
    pub volume: f32,
    pub muted: bool,
}

impl Default for DecodeStatus {
    fn default() -> Self {
        Self {
            state: jalwa_core::PlaybackState::Stopped,
            position: Duration::ZERO,
            volume: 1.0,
            muted: false,
        }
    }
}

/// Create the appropriate audio output for the platform.
fn create_output() -> Box<dyn AudioOutput> {
    #[cfg(feature = "pipewire")]
    {
        Box::new(tarang_audio::PipeWireOutput::new())
    }
    #[cfg(not(feature = "pipewire"))]
    {
        Box::new(tarang_audio::NullOutput::new())
    }
}

/// Run the decode loop. Blocks until the track ends or a `Stop` command is received.
///
/// This function is intended to be called from `std::thread::spawn`.
pub fn decode_loop(
    path: PathBuf,
    cmd_rx: mpsc::Receiver<EngineCommand>,
    status: Arc<Mutex<DecodeStatus>>,
    event_tx: mpsc::Sender<EngineEvent>,
    config: EngineConfig,
    duration: Option<Duration>,
) {
    let mut volume: f32 = 1.0;
    let mut muted = false;

    // Open decoder
    let mut decoder = match FileDecoder::open_path(&path) {
        Ok(d) => d,
        Err(e) => {
            let _ = event_tx.send(EngineEvent::Error(format!("decode open: {e}")));
            return;
        }
    };

    // Open audio output
    let mut output = create_output();
    let out_config = OutputConfig {
        sample_rate: config.sample_rate,
        channels: config.channels,
        buffer_size: config.buffer_size,
    };
    if let Err(e) = output.open(&out_config) {
        let _ = event_tx.send(EngineEvent::Error(format!("audio output open: {e}")));
        return;
    }

    let _ = event_tx.send(EngineEvent::StateChanged(jalwa_core::PlaybackState::Playing));
    let mut paused = false;
    let mut near_end_sent = false;

    // Pre-buffered next track for gapless
    let mut next_decoder: Option<FileDecoder> = None;

    loop {
        // Handle commands (non-blocking when playing, blocking when paused)
        loop {
            let cmd = if paused {
                match cmd_rx.recv() {
                    Ok(c) => Some(c),
                    Err(_) => {
                        let _ = output.flush();
                        let _ = output.close();
                        return;
                    }
                }
            } else {
                cmd_rx.try_recv().ok()
            };

            match cmd {
                Some(EngineCommand::Stop) => {
                    let _ = output.flush();
                    let _ = output.close();
                    let _ = event_tx.send(EngineEvent::StateChanged(jalwa_core::PlaybackState::Stopped));
                    return;
                }
                Some(EngineCommand::Pause) => {
                    paused = true;
                    let _ = event_tx.send(EngineEvent::StateChanged(jalwa_core::PlaybackState::Paused));
                    if let Ok(mut s) = status.lock() {
                        s.state = jalwa_core::PlaybackState::Paused;
                        s.volume = volume;
                        s.muted = muted;
                    }
                    continue;
                }
                Some(EngineCommand::Resume | EngineCommand::Play) => {
                    paused = false;
                    let _ = event_tx.send(EngineEvent::StateChanged(jalwa_core::PlaybackState::Playing));
                    break;
                }
                Some(EngineCommand::Seek(pos)) => {
                    if let Err(e) = decoder.seek(pos) {
                        let _ = event_tx.send(EngineEvent::Error(format!("seek: {e}")));
                    }
                    break;
                }
                Some(EngineCommand::Volume(v)) => {
                    volume = v.clamp(0.0, 1.0);
                }
                Some(EngineCommand::Mute(m)) => {
                    muted = m;
                }
                Some(EngineCommand::PrepareNext { path }) => {
                    match FileDecoder::open_path(&path) {
                        Ok(d) => next_decoder = Some(d),
                        Err(e) => {
                            let _ = event_tx.send(EngineEvent::Error(format!("prepare next: {e}")));
                        }
                    }
                }
                None => break,
            }
        }

        // Decode next buffer
        let buf = match decoder.next_buffer() {
            Ok(b) => b,
            Err(TarangError::EndOfStream) => {
                // Try gapless transition
                if let Some(next) = next_decoder.take() {
                    decoder = next;
                    near_end_sent = false;
                    let _ = event_tx.send(EngineEvent::TrackChanged);
                    continue;
                }
                let _ = output.flush();
                let _ = output.close();
                let _ = event_tx.send(EngineEvent::TrackFinished);
                return;
            }
            Err(e) => {
                let _ = event_tx.send(EngineEvent::Error(format!("decode: {e}")));
                let _ = output.flush();
                let _ = output.close();
                return;
            }
        };

        // Resample if needed
        let buf = if buf.sample_rate != config.sample_rate {
            match resample(&buf, config.sample_rate) {
                Ok(b) => b,
                Err(e) => {
                    tracing::warn!("resample error: {e}");
                    buf
                }
            }
        } else {
            buf
        };

        // Mix channels if needed
        let buf = if buf.channels != config.channels {
            let target = if config.channels == 1 {
                ChannelLayout::Mono
            } else {
                ChannelLayout::Stereo
            };
            match mix_channels(&buf, target) {
                Ok(b) => b,
                Err(e) => {
                    tracing::warn!("channel mix error: {e}");
                    buf
                }
            }
        } else {
            buf
        };

        // Apply volume
        let buf = if muted || (volume - 1.0).abs() > f32::EPSILON {
            let gain = if muted { 0.0 } else { volume };
            apply_volume(&buf, gain)
        } else {
            buf
        };

        // Update status
        if let Ok(mut s) = status.lock() {
            s.state = jalwa_core::PlaybackState::Playing;
            s.position = buf.timestamp;
            s.volume = volume;
            s.muted = muted;
        }

        // Check near-end for gapless prebuffer hint
        if !near_end_sent {
            if let Some(dur) = duration {
                if dur.as_secs_f64() - buf.timestamp.as_secs_f64() < 2.0 {
                    let _ = event_tx.send(EngineEvent::NearEnd);
                    near_end_sent = true;
                }
            }
        }

        // Write to output
        if let Err(e) = output.write(&buf) {
            let _ = event_tx.send(EngineEvent::Error(format!("output write: {e}")));
            let _ = output.close();
            return;
        }
    }
}

/// Apply volume gain to an AudioBuffer, returning a new buffer.
fn apply_volume(buf: &tarang_core::AudioBuffer, gain: f32) -> tarang_core::AudioBuffer {
    let samples: &[f32] = unsafe {
        std::slice::from_raw_parts(buf.data.as_ptr() as *const f32, buf.data.len() / 4)
    };
    let scaled: Vec<f32> = samples.iter().map(|s| s * gain).collect();
    let bytes = unsafe {
        std::slice::from_raw_parts(scaled.as_ptr() as *const u8, scaled.len() * 4)
    };
    tarang_core::AudioBuffer {
        data: bytes::Bytes::copy_from_slice(bytes),
        sample_format: buf.sample_format,
        channels: buf.channels,
        sample_rate: buf.sample_rate,
        num_samples: buf.num_samples,
        timestamp: buf.timestamp,
    }
}

//! jalwa-playback — Playback engine for the Jalwa media player
//!
//! Manages the decode pipeline (via tarang) and audio output (PipeWire).
//! Handles play, pause, seek, volume, and track switching.

pub mod decode_thread;

use jalwa_core::{JalwaError, PlaybackState, PlaybackStatus, Result};
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex, mpsc};
use std::time::Duration;

pub use decode_thread::{DecodeStatus, EngineCommand, EngineEvent};

/// Playback engine configuration
#[derive(Debug, Clone)]
pub struct EngineConfig {
    pub buffer_size: usize,
    pub sample_rate: u32,
    pub channels: u16,
}

impl Default for EngineConfig {
    fn default() -> Self {
        Self {
            buffer_size: 4096,
            sample_rate: 48000,
            channels: 2,
        }
    }
}

/// The playback engine — orchestrates tarang decode + audio output
pub struct PlaybackEngine {
    config: EngineConfig,
    state: PlaybackState,
    current_path: Option<PathBuf>,
    position: Duration,
    duration: Option<Duration>,
    volume: f32,
    muted: bool,
    // Channel-based communication with decode thread
    cmd_tx: Option<mpsc::Sender<EngineCommand>>,
    decode_status: Option<Arc<Mutex<DecodeStatus>>>,
    event_rx: Option<mpsc::Receiver<EngineEvent>>,
    decode_handle: Option<std::thread::JoinHandle<()>>,
}

impl PlaybackEngine {
    pub fn new(config: EngineConfig) -> Self {
        Self {
            config,
            state: PlaybackState::Stopped,
            current_path: None,
            position: Duration::ZERO,
            duration: None,
            volume: 1.0,
            muted: false,
            cmd_tx: None,
            decode_status: None,
            event_rx: None,
            decode_handle: None,
        }
    }

    /// Open a media file for playback (probe only)
    pub fn open(&mut self, path: &Path) -> Result<()> {
        if !path.exists() {
            return Err(JalwaError::NotFound(path.to_string_lossy().to_string()));
        }

        // Stop any existing playback
        self.stop();

        // Probe the file via tarang
        let file = std::fs::File::open(path)?;
        let info = tarang_audio::probe_audio(file).map_err(JalwaError::Tarang)?;

        self.duration = info.duration;
        self.current_path = Some(path.to_path_buf());
        self.position = Duration::ZERO;
        self.state = PlaybackState::Stopped;

        tracing::info!(
            path = %path.display(),
            format = %info.format,
            streams = info.streams.len(),
            "opened media file"
        );

        Ok(())
    }

    /// Start or resume playback
    pub fn play(&mut self) -> Result<()> {
        let path = self.current_path.clone().ok_or_else(|| {
            JalwaError::Playback("no file loaded".to_string())
        })?;

        if self.state == PlaybackState::Paused {
            // Resume existing decode thread
            if let Some(ref tx) = self.cmd_tx {
                let _ = tx.send(EngineCommand::Resume);
            }
            self.state = PlaybackState::Playing;
            return Ok(());
        }

        // Spawn new decode thread
        let (cmd_tx, cmd_rx) = mpsc::channel();
        let status = Arc::new(Mutex::new(DecodeStatus::default()));
        let status_clone = status.clone();
        let (event_tx, event_rx) = mpsc::channel();

        let config = self.config.clone();
        let duration = self.duration;

        let handle = std::thread::Builder::new()
            .name("jalwa-decode".into())
            .spawn(move || {
                decode_thread::decode_loop(path, cmd_rx, status_clone, event_tx, config, duration);
            })
            .map_err(|e| JalwaError::Playback(format!("spawn decode thread: {e}")))?;

        self.cmd_tx = Some(cmd_tx);
        self.decode_status = Some(status);
        self.event_rx = Some(event_rx);
        self.decode_handle = Some(handle);
        self.state = PlaybackState::Playing;

        Ok(())
    }

    /// Pause playback
    pub fn pause(&mut self) {
        if self.state == PlaybackState::Playing {
            if let Some(ref tx) = self.cmd_tx {
                let _ = tx.send(EngineCommand::Pause);
            }
            self.state = PlaybackState::Paused;
        }
    }

    /// Stop playback and reset position
    pub fn stop(&mut self) {
        if let Some(ref tx) = self.cmd_tx {
            let _ = tx.send(EngineCommand::Stop);
        }
        // Wait for decode thread to finish
        if let Some(handle) = self.decode_handle.take() {
            let _ = handle.join();
        }
        self.cmd_tx = None;
        self.decode_status = None;
        self.event_rx = None;
        self.state = PlaybackState::Stopped;
        self.position = Duration::ZERO;
    }

    /// Toggle play/pause
    pub fn toggle(&mut self) -> Result<()> {
        match self.state {
            PlaybackState::Playing => {
                self.pause();
                Ok(())
            }
            PlaybackState::Paused | PlaybackState::Stopped => self.play(),
            PlaybackState::Buffering => Ok(()),
        }
    }

    /// Seek to a position
    pub fn seek(&mut self, position: Duration) -> Result<()> {
        if self.duration.is_some_and(|dur| position > dur) {
            return Err(JalwaError::Playback("seek beyond end".to_string()));
        }
        if let Some(ref tx) = self.cmd_tx {
            let _ = tx.send(EngineCommand::Seek(position));
        }
        self.position = position;
        Ok(())
    }

    /// Seek by a relative offset (can be negative)
    pub fn seek_relative(&mut self, offset_secs: f64) -> Result<()> {
        let current = self.position().as_secs_f64();
        let new_pos = (current + offset_secs).max(0.0);
        let target = if let Some(dur) = self.duration {
            Duration::from_secs_f64(new_pos.min(dur.as_secs_f64()))
        } else {
            Duration::from_secs_f64(new_pos)
        };
        self.seek(target)
    }

    /// Set volume (0.0 to 1.0)
    pub fn set_volume(&mut self, volume: f32) {
        self.volume = volume.clamp(0.0, 1.0);
        if let Some(ref tx) = self.cmd_tx {
            let _ = tx.send(EngineCommand::Volume(self.volume));
        }
    }

    /// Get current volume
    pub fn volume(&self) -> f32 {
        self.volume
    }

    /// Toggle mute
    pub fn toggle_mute(&mut self) {
        self.muted = !self.muted;
        if let Some(ref tx) = self.cmd_tx {
            let _ = tx.send(EngineCommand::Mute(self.muted));
        }
    }

    /// Get mute state
    pub fn muted(&self) -> bool {
        self.muted
    }

    /// Get current playback state
    pub fn state(&self) -> PlaybackState {
        self.state
    }

    /// Get current position (reads from decode thread if running)
    pub fn position(&self) -> Duration {
        if let Some(ref status) = self.decode_status {
            if let Ok(s) = status.lock() {
                return s.position;
            }
        }
        self.position
    }

    /// Get current file's duration
    pub fn duration(&self) -> Option<Duration> {
        self.duration
    }

    /// Get current file path
    pub fn current_path(&self) -> Option<&Path> {
        self.current_path.as_deref()
    }

    /// Get full playback status snapshot
    pub fn status(&self) -> PlaybackStatus {
        let position = self.position();
        PlaybackStatus {
            state: self.state,
            current_item: None, // Caller maps path -> UUID
            position,
            duration: self.duration,
            volume: self.volume,
            muted: self.muted,
        }
    }

    /// Get engine config
    pub fn config(&self) -> &EngineConfig {
        &self.config
    }

    /// Get a reference to the event receiver for polling events
    pub fn events(&self) -> Option<&mpsc::Receiver<EngineEvent>> {
        self.event_rx.as_ref()
    }

    /// Prepare next track for gapless playback
    pub fn prepare_next(&self, path: &Path) {
        if let Some(ref tx) = self.cmd_tx {
            let _ = tx.send(EngineCommand::PrepareNext {
                path: path.to_path_buf(),
            });
        }
    }

    /// Poll and process engine events, updating internal state.
    /// Returns collected events for the caller to handle.
    pub fn poll_events(&mut self) -> Vec<EngineEvent> {
        let mut events = Vec::new();
        if let Some(ref rx) = self.event_rx {
            while let Ok(event) = rx.try_recv() {
                match &event {
                    EngineEvent::StateChanged(s) => self.state = *s,
                    EngineEvent::TrackFinished => {
                        self.state = PlaybackState::Stopped;
                    }
                    _ => {}
                }
                events.push(event);
            }
        }
        // Update position from decode status
        if let Some(ref status) = self.decode_status {
            if let Ok(s) = status.lock() {
                self.position = s.position;
            }
        }
        events
    }
}

impl Drop for PlaybackEngine {
    fn drop(&mut self) {
        self.stop();
    }
}

/// Format a duration as HH:MM:SS or MM:SS
pub fn format_duration(d: Duration) -> String {
    let total_secs = d.as_secs();
    let hours = total_secs / 3600;
    let mins = (total_secs % 3600) / 60;
    let secs = total_secs % 60;
    if hours > 0 {
        format!("{hours}:{mins:02}:{secs:02}")
    } else {
        format!("{mins}:{secs:02}")
    }
}

