//! Application state for the interactive TUI.

use jalwa_core::db::PersistentLibrary;
use jalwa_core::PlayQueue;
use jalwa_playback::PlaybackEngine;

/// Which view is active in the TUI.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum View {
    Library,
    NowPlaying,
    Queue,
}

impl View {
    pub fn cycle(self) -> Self {
        match self {
            Self::Library => Self::NowPlaying,
            Self::NowPlaying => Self::Queue,
            Self::Queue => Self::Library,
        }
    }
}

/// Input mode — normal navigation or text search.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum InputMode {
    Normal,
    Search,
}

/// Top-level application state for the TUI.
pub struct App {
    pub library: PersistentLibrary,
    pub engine: PlaybackEngine,
    pub queue: PlayQueue,
    pub view: View,
    pub selected_index: usize,
    pub search_query: String,
    pub search_results: Vec<usize>,
    pub input_mode: InputMode,
    pub running: bool,
}

impl App {
    pub fn new(library: PersistentLibrary, engine: PlaybackEngine) -> Self {
        Self {
            library,
            engine,
            queue: PlayQueue::new(),
            view: View::Library,
            selected_index: 0,
            search_query: String::new(),
            search_results: Vec::new(),
            input_mode: InputMode::Normal,
            running: true,
        }
    }

    /// Number of items in the current view's list.
    pub fn list_len(&self) -> usize {
        match self.view {
            View::Library => {
                if self.input_mode == InputMode::Search || !self.search_query.is_empty() {
                    self.search_results.len()
                } else {
                    self.library.library.items.len()
                }
            }
            View::Queue => self.queue.len(),
            View::NowPlaying => 0,
        }
    }

    /// Move selection up.
    pub fn select_prev(&mut self) {
        if self.selected_index > 0 {
            self.selected_index -= 1;
        }
    }

    /// Move selection down.
    pub fn select_next(&mut self) {
        let len = self.list_len();
        if len > 0 && self.selected_index < len - 1 {
            self.selected_index += 1;
        }
    }

    /// Update search results based on current query.
    pub fn update_search(&mut self) {
        if self.search_query.is_empty() {
            self.search_results.clear();
            return;
        }
        let q = self.search_query.to_lowercase();
        self.search_results = self
            .library
            .library
            .items
            .iter()
            .enumerate()
            .filter(|(_, item)| {
                item.title.to_lowercase().contains(&q)
                    || item.artist.as_ref().is_some_and(|a| a.to_lowercase().contains(&q))
                    || item.album.as_ref().is_some_and(|a| a.to_lowercase().contains(&q))
            })
            .map(|(i, _)| i)
            .collect();
        // Clamp selection
        if self.selected_index >= self.search_results.len() && !self.search_results.is_empty() {
            self.selected_index = self.search_results.len() - 1;
        }
    }

    /// Get the library index for the currently selected item.
    pub fn selected_library_index(&self) -> Option<usize> {
        if self.view != View::Library {
            return None;
        }
        if !self.search_query.is_empty() {
            self.search_results.get(self.selected_index).copied()
        } else if self.selected_index < self.library.library.items.len() {
            Some(self.selected_index)
        } else {
            None
        }
    }
}

//! jalwa-ui — UI layer for the Jalwa media player
//!
//! Terminal UI (TUI) for initial MVP, desktop GUI planned.
//! Renders playback status, library browser, and queue.

pub mod app;
pub mod tui;
pub mod widgets;

use jalwa_core::{Library, MediaItem, PlayQueue, PlaybackState, PlaybackStatus, RepeatMode};
use jalwa_playback::format_duration;
use std::time::Duration;

/// Render a playback status bar as a string
pub fn render_status_bar(status: &PlaybackStatus, item: Option<&MediaItem>) -> String {
    let state_icon = match status.state {
        PlaybackState::Playing => ">>",
        PlaybackState::Paused => "||",
        PlaybackState::Stopped => "[]",
        PlaybackState::Buffering => "..",
    };

    let title = item.map(|i| i.title.as_str()).unwrap_or("No media loaded");

    let artist = item.and_then(|i| i.artist.as_deref()).unwrap_or("");

    let position = format_duration(status.position);
    let duration = status
        .duration
        .map(format_duration)
        .unwrap_or_else(|| "--:--".to_string());

    let volume = if status.muted {
        "MUTE".to_string()
    } else {
        format!("{}%", (status.volume * 100.0) as u8)
    };

    if artist.is_empty() {
        format!("{state_icon} {title}  [{position} / {duration}]  Vol: {volume}")
    } else {
        format!("{state_icon} {artist} - {title}  [{position} / {duration}]  Vol: {volume}")
    }
}

/// Render a progress bar
pub fn render_progress_bar(progress: f64, width: usize) -> String {
    let filled = (progress * width as f64) as usize;
    let empty = width.saturating_sub(filled);
    format!("[{}{}]", "=".repeat(filled.min(width)), " ".repeat(empty))
}

/// Render the play queue summary
pub fn render_queue_summary(queue: &PlayQueue) -> String {
    let pos = queue
        .position
        .map(|p| format!("{}/{}", p + 1, queue.len()))
        .unwrap_or_else(|| format!("0/{}", queue.len()));

    let repeat = match queue.repeat_mode {
        RepeatMode::Off => "",
        RepeatMode::One => " [R1]",
        RepeatMode::All => " [RA]",
    };

    let shuffle = if queue.shuffle { " [S]" } else { "" };

    format!("Queue: {pos}{repeat}{shuffle}")
}

/// Render a library item as a single line
pub fn render_library_item(item: &MediaItem, index: usize) -> String {
    let duration = item
        .duration
        .map(format_duration)
        .unwrap_or_else(|| "?:??".to_string());

    let artist = item.artist.as_deref().unwrap_or("Unknown");

    format!(
        "{:>3}. {} - {} [{}] ({})",
        index + 1,
        artist,
        item.title,
        duration,
        item.media_type
    )
}

/// Render library stats
pub fn render_library_stats(library: &Library) -> String {
    let total = library.items.len();
    let audio = library.audio_items().len();
    let video = library.video_items().len();
    let playlists = library.playlists.len();

    let total_duration: Duration = library.items.iter().filter_map(|i| i.duration).sum();

    format!(
        "Library: {} items ({} audio, {} video), {} playlists, total: {}",
        total,
        audio,
        video,
        playlists,
        format_duration(total_duration)
    )
}

