        let mut lib = Library::new();
        lib.add_item(make_item("Song 1", "A", 180));
        lib.add_item(make_item("Song 2", "B", 240));
        lib.create_playlist("Favs");

        let stats = render_library_stats(&lib);
        assert!(stats.contains("2 items"));
        assert!(stats.contains("2 audio"));
        assert!(stats.contains("0 video"));
        assert!(stats.contains("1 playlists"));
        assert!(stats.contains("7:00")); // 180 + 240 = 420s = 7:00
    }
}

//! Interactive terminal UI event loop.

use std::io;
use std::time::Duration;

use crossterm::event::{self, Event, KeyCode, KeyModifiers};
use crossterm::terminal::{self, EnterAlternateScreen, LeaveAlternateScreen};
use crossterm::execute;
use ratatui::Terminal;
use ratatui::backend::CrosstermBackend;

use jalwa_playback::EngineEvent;

use crate::app::{App, InputMode, View};
use crate::widgets;

/// Run the interactive TUI. Blocks until the user quits.
pub fn run(mut app: App) -> io::Result<()> {
    // Setup terminal
    terminal::enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen)?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    let tick_rate = Duration::from_millis(50);

    while app.running {
        // Draw
        terminal.draw(|frame| {
            widgets::render(frame, &app);
        })?;

        // Poll engine events
        let events = app.engine.poll_events();
        for ev in &events {
            match ev {
                EngineEvent::TrackFinished => {
                    // Advance queue
                    if let Some(next_id) = app.queue.advance() {
                        if let Some(item) = app.library.library.find_by_id(next_id) {
                            let path = item.path.clone();
                            let _ = app.engine.open(&path);
                            let _ = app.engine.play();
                        }
                    }
                }
                EngineEvent::TrackChanged => {
                    // Gapless transition happened in decode thread
                    if let Some(_) = app.queue.advance() {
                        // Queue advanced
                    }
                }
                EngineEvent::NearEnd => {
                    // Prepare next track for gapless playback
                    if let Some(next_pos) = app.queue.position.map(|p| p + 1) {
                        if let Some(next_id) = app.queue.items.get(next_pos) {
                            if let Some(item) = app.library.library.find_by_id(*next_id) {
                                app.engine.prepare_next(&item.path);
                            }
                        }
                    }
                }
                _ => {}
            }
        }

        // Handle input
        if event::poll(tick_rate)? {
            if let Event::Key(key) = event::read()? {
                // Ctrl+C always quits
                if key.modifiers.contains(KeyModifiers::CONTROL) && key.code == KeyCode::Char('c')
                {
                    app.running = false;
                    continue;
                }

                match app.input_mode {
                    InputMode::Search => handle_search_input(&mut app, key.code),
                    InputMode::Normal => handle_normal_input(&mut app, key.code),
                }
            }
        }
    }

    // Restore terminal
    terminal::disable_raw_mode()?;
    execute!(terminal.backend_mut(), LeaveAlternateScreen)?;
    terminal.show_cursor()?;

    // Cleanup
    app.engine.stop();

    Ok(())
}

fn handle_normal_input(app: &mut App, key: KeyCode) {
    match key {
        KeyCode::Char('q') => app.running = false,

        KeyCode::Char(' ') => {
            let _ = app.engine.toggle();
        }

        KeyCode::Left => {
            let _ = app.engine.seek_relative(-10.0);
        }
        KeyCode::Right => {
            let _ = app.engine.seek_relative(10.0);
        }

        KeyCode::Up => app.select_prev(),
        KeyCode::Down => app.select_next(),

        KeyCode::Enter => {
            match app.view {
                View::Library => {
                    if let Some(idx) = app.selected_library_index() {
                        let item = &app.library.library.items[idx];
                        let path = item.path.clone();
                        let id = item.id;
                        let _ = app.engine.open(&path);
                        let _ = app.engine.play();
                        // Also enqueue if queue is empty
                        if app.queue.is_empty() {
                            app.queue.enqueue(id);
                        }
                    }
                }
                View::Queue => {
                    // Jump to selected queue item
                    if app.selected_index < app.queue.len() {
                        app.queue.position = Some(app.selected_index);
                        if let Some(id) = app.queue.current() {
                            if let Some(item) = app.library.library.find_by_id(id) {
                                let path = item.path.clone();
                                let _ = app.engine.open(&path);
                                let _ = app.engine.play();
                            }
                        }
                    }
                }
                _ => {}
            }
        }

        KeyCode::Char('/') => {
            app.input_mode = InputMode::Search;
            app.search_query.clear();
            app.search_results.clear();
            app.view = View::Library;
        }

        KeyCode::Tab => {
            app.view = app.view.cycle();
            app.selected_index = 0;
        }

        KeyCode::Char('+') | KeyCode::Char('=') => {
            let vol = (app.engine.volume() + 0.05).min(1.0);
            app.engine.set_volume(vol);
        }
        KeyCode::Char('-') => {
            let vol = (app.engine.volume() - 0.05).max(0.0);
            app.engine.set_volume(vol);
        }
        KeyCode::Char('m') => {
            app.engine.toggle_mute();
        }

        KeyCode::Char('n') => {
            // Next track
            if let Some(next_id) = app.queue.advance() {
                if let Some(item) = app.library.library.find_by_id(next_id) {
                    let path = item.path.clone();
                    let _ = app.engine.open(&path);
                    let _ = app.engine.play();
                }
            }
        }
        KeyCode::Char('p') => {
            // Previous track
            if let Some(prev_id) = app.queue.go_back() {
                if let Some(item) = app.library.library.find_by_id(prev_id) {
                    let path = item.path.clone();
                    let _ = app.engine.open(&path);
                    let _ = app.engine.play();
                }
            }
        }

        KeyCode::Char('r') => {
            app.queue.repeat_mode = app.queue.repeat_mode.cycle();
        }
        KeyCode::Char('s') => {
            app.queue.shuffle = !app.queue.shuffle;
        }

        KeyCode::Char('a') => {
            // Add selected library item to queue
            if app.view == View::Library {
                if let Some(idx) = app.selected_library_index() {
                    let id = app.library.library.items[idx].id;
                    app.queue.enqueue(id);
                }
            }
        }

        KeyCode::Char('d') => {
            // Remove selected item from queue
            if app.view == View::Queue && app.selected_index < app.queue.len() {
                app.queue.items.remove(app.selected_index);
                if app.selected_index >= app.queue.len() && app.queue.len() > 0 {
                    app.selected_index = app.queue.len() - 1;
                }
                // Fix position
                if let Some(pos) = app.queue.position {
                    if app.selected_index <= pos && pos > 0 {
                        app.queue.position = Some(pos - 1);
                    }
                }
            }
        }

        KeyCode::Char('c') => {
            // Clear queue
            if app.view == View::Queue {
                app.queue.clear();
                app.selected_index = 0;
            }
        }

        _ => {}
    }
}

fn handle_search_input(app: &mut App, key: KeyCode) {
    match key {
        KeyCode::Esc => {
            app.input_mode = InputMode::Normal;
            app.search_query.clear();
            app.search_results.clear();
            app.selected_index = 0;
        }
        KeyCode::Enter => {
            app.input_mode = InputMode::Normal;
            // Keep search results visible
        }
        KeyCode::Backspace => {
            app.search_query.pop();
            app.update_search();
            app.selected_index = 0;
        }
        KeyCode::Char(c) => {
            app.search_query.push(c);
            app.update_search();
            app.selected_index = 0;
        }
        KeyCode::Up => app.select_prev(),
        KeyCode::Down => app.select_next(),
        _ => {}
    }
}

//! Ratatui widgets for the Jalwa TUI.

use jalwa_core::{MediaItem, PlaybackState, RepeatMode};
use jalwa_playback::format_duration;
use ratatui::layout::{Constraint, Direction, Layout, Rect};
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span};
use ratatui::widgets::{Block, Borders, Gauge, List, ListItem, ListState, Paragraph};
use ratatui::Frame;
use crate::app::{App, InputMode, View};

/// Render the full TUI layout.
pub fn render(frame: &mut Frame, app: &App) {
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(2), // status bar + progress
            Constraint::Min(5),   // main view
            Constraint::Length(1), // keybind help
        ])
        .split(frame.area());

    render_status_area(frame, chunks[0], app);
    render_main_view(frame, chunks[1], app);
    render_keybinds(frame, chunks[2], app);
}

fn render_status_area(frame: &mut Frame, area: Rect, app: &App) {
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([Constraint::Length(1), Constraint::Length(1)])
        .split(area);

    // Status bar
    let status = app.engine.status();
    let state_icon = match status.state {
        PlaybackState::Playing => "▶",
        PlaybackState::Paused => "⏸",
        PlaybackState::Stopped => "⏹",
        PlaybackState::Buffering => "…",
    };

    let now_playing = app.engine.current_path().and_then(|p| {
        app.library.library.find_by_path(p)
    });

    let title_str = match now_playing {
        Some(item) => {
            let artist = item.artist.as_deref().unwrap_or("");
            if artist.is_empty() {
                item.title.clone()
            } else {
                format!("{} - {}", artist, item.title)
            }
        }
        None => "No media loaded".to_string(),
    };

    let position = format_duration(status.position);
    let duration = status
        .duration
        .map(format_duration)
        .unwrap_or_else(|| "--:--".to_string());

    let volume = if status.muted {
        "MUTE".to_string()
    } else {
        format!("{}%", (status.volume * 100.0) as u8)
    };

    let status_line = Line::from(vec![
        Span::styled(
            format!(" {state_icon} "),
            Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD),
        ),
        Span::raw(&title_str),
        Span::raw("  "),
        Span::styled(
            format!("[{position} / {duration}]"),
            Style::default().fg(Color::DarkGray),
        ),
        Span::raw("  "),
        Span::styled(volume, Style::default().fg(Color::Yellow)),
    ]);

    frame.render_widget(Paragraph::new(status_line), chunks[0]);

    // Progress bar
    let progress = status.progress().unwrap_or(0.0);
    let gauge = Gauge::default()
        .gauge_style(Style::default().fg(Color::Cyan).bg(Color::DarkGray))
        .ratio(progress.clamp(0.0, 1.0));
    frame.render_widget(gauge, chunks[1]);
}

fn render_main_view(frame: &mut Frame, area: Rect, app: &App) {
    match app.view {
        View::Library => render_library_view(frame, area, app),
        View::NowPlaying => render_now_playing_view(frame, area, app),
        View::Queue => render_queue_view(frame, area, app),
    }
}

fn render_library_view(frame: &mut Frame, area: Rect, app: &App) {
    let header = if !app.search_query.is_empty() {
        format!(
            "Library ({} matches) [/{}]",
            app.search_results.len(),
            app.search_query
        )
    } else {
        format!("Library ({} items)", app.library.library.items.len())
    };

    let block = Block::default()
        .borders(Borders::TOP)
        .title(header);

    let items: Vec<ListItem> = if !app.search_query.is_empty() {
        app.search_results
            .iter()
            .enumerate()
            .filter_map(|(display_idx, &lib_idx)| {
                app.library.library.items.get(lib_idx).map(|item| {
                    make_list_item(item, display_idx)
                })
            })
            .collect()
    } else {
        app.library
            .library
            .items
            .iter()
            .enumerate()
            .map(|(i, item)| make_list_item(item, i))
            .collect()
    };

    let mut state = ListState::default();
    if !items.is_empty() {
        state.select(Some(app.selected_index.min(items.len().saturating_sub(1))));
    }

    let list = List::new(items)
        .block(block)
        .highlight_style(
            Style::default()
                .fg(Color::Black)
                .bg(Color::Cyan)
                .add_modifier(Modifier::BOLD),
        )
        .highlight_symbol("▸ ");

    frame.render_stateful_widget(list, area, &mut state);
}

fn render_now_playing_view(frame: &mut Frame, area: Rect, app: &App) {
    let block = Block::default()
        .borders(Borders::TOP)
        .title("Now Playing");

    let now_playing = app.engine.current_path().and_then(|p| {
        app.library.library.find_by_path(p)
    });

    let text = match now_playing {
        Some(item) => {
            let artist = item.artist.as_deref().unwrap_or("Unknown Artist");
            let album = item.album.as_deref().unwrap_or("Unknown Album");
            let duration = item
                .duration
                .map(format_duration)
                .unwrap_or_else(|| "?:??".to_string());
            let codec = item
                .audio_codec
                .map(|c| c.to_string())
                .unwrap_or_else(|| "?".to_string());

            vec![
                Line::from(""),
                Line::from(vec![Span::styled(
                    &item.title,
                    Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD),
                )]),
                Line::from(vec![Span::styled(artist, Style::default().fg(Color::White))]),
                Line::from(vec![Span::styled(album, Style::default().fg(Color::DarkGray))]),
                Line::from(""),
                Line::from(format!("Duration: {duration}  Codec: {codec}  Format: {}", item.format)),
                Line::from(format!(
                    "Plays: {}  Rating: {}",
                    item.play_count,
                    item.rating.map(|r| format!("{r}/5")).unwrap_or_else(|| "-".to_string())
                )),
            ]
        }
        None => vec![
            Line::from(""),
            Line::from("Nothing playing"),
            Line::from("Select a track from the Library view and press Enter"),
        ],
    };

    frame.render_widget(Paragraph::new(text).block(block), area);
}

fn render_queue_view(frame: &mut Frame, area: Rect, app: &App) {
    let header = format!(
        "Queue ({} items){}{}",
        app.queue.len(),
        match app.queue.repeat_mode {
            RepeatMode::Off => "",
            RepeatMode::One => " [R1]",
            RepeatMode::All => " [RA]",
        },
        if app.queue.shuffle { " [S]" } else { "" }
    );

    let block = Block::default()
        .borders(Borders::TOP)
        .title(header);

    let items: Vec<ListItem> = app
        .queue
        .items
        .iter()
        .enumerate()
        .map(|(i, id)| {
            let is_current = app.queue.position == Some(i);
            let prefix = if is_current { "▸ " } else { "  " };
            let title = app
                .library
                .library
                .find_by_id(*id)
                .map(|item| {
                    let artist = item.artist.as_deref().unwrap_or("Unknown");
                    format!("{}{:>3}. {} - {}", prefix, i + 1, artist, item.title)
                })
                .unwrap_or_else(|| format!("{}{:>3}. (unknown)", prefix, i + 1));
            ListItem::new(title)
        })
        .collect();

    let mut state = ListState::default();
    if !items.is_empty() && app.view == View::Queue {
        state.select(Some(app.selected_index.min(items.len().saturating_sub(1))));
    }

    let list = List::new(items)
        .block(block)
        .highlight_style(
            Style::default()
                .fg(Color::Black)
                .bg(Color::Cyan)
                .add_modifier(Modifier::BOLD),
        );

    frame.render_stateful_widget(list, area, &mut state);
}

fn render_keybinds(frame: &mut Frame, area: Rect, app: &App) {
    let binds = if app.input_mode == InputMode::Search {
        "type to search | Esc:cancel | Enter:select"
    } else {
        "␣:play/pause  /:search  ←→:seek  ↑↓:nav  Enter:play  Tab:view  a:enqueue  q:quit  +/-:vol  m:mute  n/p:next/prev  r:repeat  s:shuffle"
    };
    let line = Line::from(Span::styled(binds, Style::default().fg(Color::DarkGray)));
    frame.render_widget(Paragraph::new(line), area);
}

fn make_list_item(item: &MediaItem, index: usize) -> ListItem<'static> {
    let artist = item.artist.as_deref().unwrap_or("Unknown");
    let duration = item
        .duration
        .map(format_duration)
        .unwrap_or_else(|| "?:??".to_string());
    ListItem::new(format!(
        "{:>3}. {} - {} [{}]",
        index + 1,
        artist,
        item.title,
        duration
    ))
}

//! jalwa — AI-native media player for AGNOS
//!
//! Jalwa (Persian: manifestation/display) is a media player built on the
//! Tarang media framework. Pure Rust audio, AI-powered recommendations,
//! smart playlists, and transcription routing via hoosh.

use anyhow::Result;
use clap::{Parser, Subcommand};
use std::path::PathBuf;
use std::sync::{Arc, Mutex};
use std::time::Duration;

#[derive(Parser)]
#[command(name = "jalwa", version, about = "AI-native media player for AGNOS")]
struct Cli {
    #[command(subcommand)]
    command: Option<Commands>,
}

#[derive(Subcommand)]
enum Commands {
    /// Play a media file
    Play {
        /// Path to media file
        path: String,
    },
    /// Probe a media file and display info
    Info {
        /// Path to media file
        path: String,
    },
    /// Search the library
    Search {
        /// Search query
        query: String,
    },
    /// Show library statistics
    Stats,
    /// Scan a directory and add files to the library
    Scan {
        /// Directory to scan
        directory: String,
    },
    /// List all items in the library
    Library,
    /// Export a playlist to M3U
    Export {
        /// Playlist name
        name: String,
        /// Output M3U file path
        output: String,
    },
    /// Import an M3U playlist
    Import {
        /// M3U file path
        file: String,
    },
    /// Launch interactive TUI
    Tui,
    /// Run as MCP server on stdio
    Mcp,
}

fn db_path() -> PathBuf {
    jalwa_core::db::default_db_path()
}

fn open_library() -> Result<jalwa_core::db::PersistentLibrary> {
    let path = db_path();
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    Ok(jalwa_core::db::PersistentLibrary::open(&path)?)
}

#[tokio::main]
async fn main() -> Result<()> {
    tracing_subscriber::fmt()
        .with_env_filter(tracing_subscriber::EnvFilter::from_default_env())
        .init();

    let cli = Cli::parse();

    match cli.command {
        Some(Commands::Play { path }) => cmd_play(&path)?,
        Some(Commands::Info { path }) => cmd_info(&path)?,
        Some(Commands::Search { query }) => cmd_search(&query)?,
        Some(Commands::Stats) => cmd_stats()?,
        Some(Commands::Scan { directory }) => cmd_scan(&directory)?,
        Some(Commands::Library) => cmd_library()?,
        Some(Commands::Export { name, output }) => cmd_export(&name, &output)?,
        Some(Commands::Import { file }) => cmd_import(&file)?,
        Some(Commands::Tui) | None => cmd_tui()?,
        Some(Commands::Mcp) => cmd_mcp().await?,
    }

    Ok(())
}

fn cmd_play(path: &str) -> Result<()> {
    let mut engine = jalwa_playback::PlaybackEngine::new(jalwa_playback::EngineConfig::default());

    let p = std::path::Path::new(path);
    engine.open(p)?;

    println!(
        "Loaded: {} ({})",
        p.file_name()
            .map(|f| f.to_string_lossy().to_string())
            .unwrap_or_default(),
        engine
            .duration()
            .map(jalwa_playback::format_duration)
            .unwrap_or_else(|| "unknown duration".to_string())
    );

    engine.play()?;

    // Block until track finishes or Ctrl+C
    let running = Arc::new(std::sync::atomic::AtomicBool::new(true));
    let r = running.clone();
    ctrlc_handler(r);

    while running.load(std::sync::atomic::Ordering::Relaxed) {
        let events = engine.poll_events();
        for ev in &events {
            match ev {
                jalwa_playback::EngineEvent::TrackFinished => {
                    println!("\nFinished.");
                    running.store(false, std::sync::atomic::Ordering::Relaxed);
                }
                jalwa_playback::EngineEvent::Error(e) => {
                    eprintln!("\nError: {e}");
                    running.store(false, std::sync::atomic::Ordering::Relaxed);
                }
                _ => {}
            }
        }

        if running.load(std::sync::atomic::Ordering::Relaxed) {
            let status = engine.status();
            print!(
                "\r{} {}",
                jalwa_ui::render_status_bar(&status, None),
                jalwa_ui::render_progress_bar(status.progress().unwrap_or(0.0), 30)
            );
            use std::io::Write;
            let _ = std::io::stdout().flush();
            std::thread::sleep(Duration::from_millis(500));
        }
    }

    engine.stop();
    println!();
    Ok(())
}

fn cmd_info(path: &str) -> Result<()> {
    let file = std::fs::File::open(path)?;
    let info = tarang_audio::probe_audio(file)?;

    println!("File:     {path}");
    println!("Format:   {}", info.format);
    if let Some(d) = info.duration {
        println!("Duration: {}", jalwa_playback::format_duration(d));
    }
    println!("Streams:  {}", info.streams.len());

    for (i, stream) in info.streams.iter().enumerate() {
        match stream {
            tarang_core::StreamInfo::Audio(a) => {
                println!(
                    "  [{}] Audio: {} {}Hz {}ch",
                    i, a.codec, a.sample_rate, a.channels
                );
            }
            tarang_core::StreamInfo::Video(v) => {
                println!(
                    "  [{}] Video: {} {}x{} {:.1}fps",
                    i, v.codec, v.width, v.height, v.frame_rate
                );
            }
            tarang_core::StreamInfo::Subtitle { language } => {
                println!(
                    "  [{}] Subtitle: {}",
                    i,
                    language.as_deref().unwrap_or("unknown")
                );
            }
        }
    }

    // AI analysis
    let analysis = tarang_ai::analyze_media(&info);
    println!("\nAI Analysis:");
    println!("  Type:       {}", analysis.content_type);
    println!("  Quality:    {:.0}/100", analysis.quality_score);
    println!("  Tags:       {}", analysis.tags.join(", "));
    if let Some(rec) = analysis.codec_recommendation {
        println!("  Suggestion: {rec}");
    }

    Ok(())
}

fn cmd_search(query: &str) -> Result<()> {
    let plib = open_library()?;
    let results = plib.library.search(query);
    if results.is_empty() {
        println!("No results for '{query}'");
    } else {
        for (i, item) in results.iter().enumerate() {
            println!("{}", jalwa_ui::render_library_item(item, i));
        }
    }
    Ok(())
}

fn cmd_stats() -> Result<()> {
    let plib = open_library()?;
    println!("{}", jalwa_ui::render_library_stats(&plib.library));
    Ok(())
}

fn cmd_scan(directory: &str) -> Result<()> {
    let dir = std::path::Path::new(directory);
    let mut plib = open_library()?;

    println!("Scanning {}...", dir.display());
    let scanned = jalwa_core::scanner::scan_directory(dir)?;
    println!("Found {} media files", scanned.len());

    let mut added = 0;
    for file in scanned {
        let path = file.path.clone();
        // Skip if already in library
        if plib.library.find_by_path(&path).is_some() {
            continue;
        }
        let item = jalwa_core::scanner::scanned_to_media_item(file);
        plib.add_item(item)?;
        added += 1;
    }

    plib.add_scan_path(dir.to_path_buf())?;
    println!("Added {added} new items to library");
    println!("{}", jalwa_ui::render_library_stats(&plib.library));
    Ok(())
}

fn cmd_library() -> Result<()> {
    let plib = open_library()?;
    if plib.library.items.is_empty() {
        println!("Library is empty. Use 'jalwa scan <directory>' to add files.");
    } else {
        for (i, item) in plib.library.items.iter().enumerate() {
            println!("{}", jalwa_ui::render_library_item(item, i));
        }
        println!("\n{}", jalwa_ui::render_library_stats(&plib.library));
    }
    Ok(())
}

fn cmd_export(name: &str, output: &str) -> Result<()> {
    let plib = open_library()?;
    let playlist = plib
        .library
        .playlists
        .iter()
        .find(|p| p.name.eq_ignore_ascii_case(name))
        .ok_or_else(|| anyhow::anyhow!("playlist '{name}' not found"))?;

    jalwa_core::playlist_io::save_m3u(playlist, &plib.library, std::path::Path::new(output))?;
    println!("Exported '{}' ({} items) to {output}", playlist.name, playlist.len());
    Ok(())
}

fn cmd_import(file: &str) -> Result<()> {
    let mut plib = open_library()?;
    let paths = jalwa_core::playlist_io::load_m3u(std::path::Path::new(file))?;

    let playlist_name = std::path::Path::new(file)
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("Imported")
        .to_string();

    let mut playlist = jalwa_core::Playlist::new(&playlist_name);
    let mut added = 0;

    for path in &paths {
        // Add to library if not already present
        if plib.library.find_by_path(path).is_none() {
            match jalwa_core::scanner::scan_directory(path.parent().unwrap_or(path)) {
                Ok(scanned) => {
                    for s in scanned {
                        if s.path == *path {
                            let item = jalwa_core::scanner::scanned_to_media_item(s);
                            let _ = plib.add_item(item);
                            break;
                        }
                    }
                }
                Err(_) => continue,
            }
        }
        if let Some(item) = plib.library.find_by_path(path) {
            playlist.add(item.id);
            added += 1;
        }
    }

    plib.save_playlist(&playlist)?;
    println!("Imported '{playlist_name}' with {added} tracks");
    Ok(())
}

fn cmd_tui() -> Result<()> {
    let plib = open_library()?;
    let engine = jalwa_playback::PlaybackEngine::new(jalwa_playback::EngineConfig::default());
    let app = jalwa_ui::app::App::new(plib, engine);
    jalwa_ui::tui::run(app)?;
    Ok(())
}

async fn cmd_mcp() -> Result<()> {
    use serde_json::{Value, json};
    use tokio::io::{AsyncBufReadExt, BufReader};

    let plib = Arc::new(Mutex::new(open_library()?));

    let stdin = BufReader::new(tokio::io::stdin());
    let mut lines = stdin.lines();

    while let Ok(Some(line)) = lines.next_line().await {
        let request: Value = match serde_json::from_str(&line) {
            Ok(v) => v,
            Err(_) => continue,
        };

        let method = request["method"].as_str().unwrap_or("");
        let id = &request["id"];

        let result = match method {
            "initialize" => json!({
                "protocolVersion": "2024-11-05",
                "capabilities": { "tools": { "listChanged": false } },
                "serverInfo": { "name": "jalwa", "version": env!("CARGO_PKG_VERSION") }
            }),
            "tools/list" => json!({
                "tools": [
                    {
                        "name": "jalwa_play",
                        "description": "Play a media file (audio or video)",
                        "inputSchema": {
                            "type": "object",
                            "properties": { "path": { "type": "string" } },
                            "required": ["path"]
                        }
                    },
                    {
                        "name": "jalwa_pause",
                        "description": "Pause current playback",
                        "inputSchema": { "type": "object", "properties": {} }
                    },
                    {
                        "name": "jalwa_status",
                        "description": "Get current playback status (state, position, volume)",
                        "inputSchema": { "type": "object", "properties": {} }
                    },
                    {
                        "name": "jalwa_search",
                        "description": "Search the media library by title, artist, album, or tag",
                        "inputSchema": {
                            "type": "object",
                            "properties": { "query": { "type": "string" } },
                            "required": ["query"]
                        }
                    },
                    {
                        "name": "jalwa_recommend",
                        "description": "Get AI-powered media recommendations based on a seed item",
                        "inputSchema": {
                            "type": "object",
                            "properties": {
                                "item_id": { "type": "string", "description": "UUID of seed media item" },
                                "max": { "type": "integer", "description": "Max recommendations (default 5)" }
                            },
                            "required": ["item_id"]
                        }
                    }
                ]
            }),
            "tools/call" => {
                let tool_name = request["params"]["name"].as_str().unwrap_or("");
                let args = &request["params"]["arguments"];
                handle_tool_call(tool_name, args, &plib)
            }
            _ => json!({ "error": format!("unknown method: {method}") }),
        };

        let response = json!({
            "jsonrpc": "2.0",
            "id": id,
            "result": result
        });
        println!("{}", serde_json::to_string(&response)?);
    }

    Ok(())
}

fn handle_tool_call(
    name: &str,
    args: &serde_json::Value,
    plib: &Arc<Mutex<jalwa_core::db::PersistentLibrary>>,
) -> serde_json::Value {
    use serde_json::json;

    match name {
        "jalwa_play" => {
            let path = args["path"].as_str().unwrap_or("");
            let mut engine =
                jalwa_playback::PlaybackEngine::new(jalwa_playback::EngineConfig::default());
            match engine.open(std::path::Path::new(path)) {
                Ok(()) => {
                    let _ = engine.play();
                    let status = engine.status();
                    json!({
                        "content": [{ "type": "text", "text": format!("Playing: {path}\n{}", jalwa_ui::render_status_bar(&status, None)) }]
                    })
                }
                Err(e) => {
                    json!({ "content": [{ "type": "text", "text": format!("error: {e}") }], "isError": true })
                }
            }
        }
        "jalwa_pause" => {
            json!({ "content": [{ "type": "text", "text": "paused" }] })
        }
        "jalwa_status" => {
            let engine =
                jalwa_playback::PlaybackEngine::new(jalwa_playback::EngineConfig::default());
            let status = engine.status();
            json!({
                "content": [{ "type": "text", "text": serde_json::to_string_pretty(&status).unwrap_or_default() }]
            })
        }
        "jalwa_search" => {
            let query = args["query"].as_str().unwrap_or("");
            let lib = plib.lock().unwrap();
            let results = lib.library.search(query);
            let text = if results.is_empty() {
                format!("No results for '{query}'")
            } else {
                results
                    .iter()
                    .enumerate()
                    .map(|(i, item)| jalwa_ui::render_library_item(item, i))
                    .collect::<Vec<_>>()
                    .join("\n")
            };
            json!({ "content": [{ "type": "text", "text": text }] })
        }
        "jalwa_recommend" => {
            let item_id_str = args["item_id"].as_str().unwrap_or("");
            let max = args["max"].as_u64().unwrap_or(5) as usize;
            let lib = plib.lock().unwrap();

            match uuid::Uuid::parse_str(item_id_str) {
                Ok(seed_id) => {
                    let recs = jalwa_ai::recommend(&lib.library, seed_id, max);
                    if recs.is_empty() {
                        json!({ "content": [{ "type": "text", "text": "No recommendations found" }] })
                    } else {
                        let text: Vec<String> = recs.iter().map(|r| {
                            let title = lib.library.find_by_id(r.item_id)
                                .map(|i| {
                                    let artist = i.artist.as_deref().unwrap_or("Unknown");
                                    format!("{} - {}", artist, i.title)
                                })
                                .unwrap_or_else(|| r.item_id.to_string());
                            let reasons: Vec<String> = r.reasons.iter().map(|r| r.to_string()).collect();
                            format!("  {:.0}% {} ({})", r.score, title, reasons.join(", "))
                        }).collect();
                        json!({ "content": [{ "type": "text", "text": text.join("\n") }] })
                    }
                }
                Err(_) => {
                    json!({ "content": [{ "type": "text", "text": "invalid item_id UUID" }], "isError": true })
                }
            }
        }
        _ => {
            json!({ "content": [{ "type": "text", "text": format!("unknown tool: {name}") }], "isError": true })
        }
    }
}

fn ctrlc_handler(running: Arc<std::sync::atomic::AtomicBool>) {
    let _ = ctrlc::install_handler(move || {
        running.store(false, std::sync::atomic::Ordering::Relaxed);
    });
}

/// Simple ctrlc handler module (inline, no extra dep needed — uses signal directly)
mod ctrlc {
    pub fn install_handler(handler: impl Fn() + Send + 'static) -> Result<(), std::io::Error> {
        // Use a simple signal handler via libc
        unsafe {
            libc::signal(libc::SIGINT, signal_handler as *const () as libc::sighandler_t);
        }
        // Store handler in a static
        *HANDLER.lock().unwrap() = Some(Box::new(handler));
        Ok(())
    }

    static HANDLER: std::sync::Mutex<Option<Box<dyn Fn() + Send>>> = std::sync::Mutex::new(None);

    extern "C" fn signal_handler(_: libc::c_int) {
        if let Ok(guard) = HANDLER.lock() {
            if let Some(ref handler) = *guard {
                handler();
            }
        }
    }
}
